import React, { useEffect, useState } from 'react';
import { adminService, userService } from '../../services/api';
import '../../styles/dashboard.css';
import '../../styles/admin/admin-users.css';
import '../../styles/admin-layout.css';

const ROLE_OPTIONS = [
  { value: 'OWNER', label: 'Owner' },
  { value: 'MANAGER', label: 'Quản lý (Manager)' },
  { value: 'TECHNICIAN', label: 'Kỹ thuật (Technician)' },
  { value: 'WORKER', label: 'Công nhân (Worker)' },
  { value: 'ACCOUNTANT', label: 'Kế toán (Accountant)' },
  { value: 'STOREKEEPER', label: 'Quản lý kho (Storekeeper)' },
];

const AdminUsers = () => {
  const [users, setUsers] = useState([]);
  const [farms, setFarms] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(null);
  const [showModal, setShowModal] = useState(false);
  const [selectedUser, setSelectedUser] = useState(null);
  const [formData, setFormData] = useState({
    fullName: '',
    username: '',
    email: '',
    phone: '',
    password: '',
    role: 'WORKER',
    farmId: '',
  });

  useEffect(() => {
    fetchUsers();
    fetchFarms();
  }, []);

  const fetchUsers = async () => {
    try {
      setLoading(true);
      const response = await adminService.getAllUsers();
      setUsers(response.data.data || []);
    } catch (err) {
      setError('Lỗi tải danh sách người dùng');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const fetchFarms = async () => {
    try {
      const response = await adminService.getFarms();
      setFarms(response.data.data || []);
    } catch (err) {
      console.error('Lỗi tải danh sách trại nuôi:', err);
    }
  };

  const handleOpenModal = (user = null) => {
    if (user) {
      setSelectedUser(user);
      setFormData({
        fullName: user.full_name || '',
        username: user.username || '',
        email: user.email || '',
        phone: user.phone || '',
        password: '',
        role: String(user.role || 'WORKER').toUpperCase(),
        farmId: user.farm_id || '',
      });
    } else {
      setSelectedUser(null);
      setFormData({
        fullName: '',
        username: '',
        email: '',
        phone: '',
        password: '',
        role: 'WORKER',
        farmId: '',
      });
    }
    setShowModal(true);
  };

  const handleCloseModal = () => {
    setShowModal(false);
    setSelectedUser(null);
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(null);
    setSuccess(null);

    try {
      if (selectedUser) {
        await userService.updateUser(selectedUser.user_id, {
          full_name: formData.fullName,
          email: formData.email,
          phone: formData.phone,
        });
        setSuccess('Cập nhật người dùng thành công');
      } else {
        await adminService.createUser({
          fullName: formData.fullName,
          username: formData.username,
          email: formData.email,
          phone: formData.phone,
          role: formData.role,
          password: formData.password,
          farmId: formData.farmId,
        });
        setSuccess('Tạo người dùng mới thành công');
      }

      handleCloseModal();
      fetchUsers();
    } catch (err) {
      setError(err.response?.data?.message || 'Lỗi xử lý');
      console.error(err);
    }
  };

  const handleLockUser = async (userId) => {
    if (!window.confirm('Bạn có chắc chắn muốn khóa tài khoản này?')) {
      return;
    }

    try {
      await adminService.lockUser(userId);
      setSuccess('Khóa tài khoản thành công');
      fetchUsers();
    } catch (err) {
      const errorMsg = err.response?.data?.message || 'Lỗi khóa tài khoản';
      setError(errorMsg);
      console.error(err);
    }
  };

  const handleUnlockUser = async (userId) => {
    try {
      await adminService.unlockUser(userId);
      setSuccess('Mở khóa tài khoản thành công');
      fetchUsers();
    } catch (err) {
      const errorMsg = err.response?.data?.message || 'Lỗi mở khóa tài khoản';
      setError(errorMsg);
      console.error(err);
    }
  };

  const handleResetPassword = async (userId) => {
    if (!window.confirm('Bạn có chắc chắn muốn reset mật khẩu tài khoản này?')) {
      return;
    }

    try {
      await userService.resetPassword(userId);
      setSuccess('Reset mật khẩu thành công (mật khẩu mặc định: 123456)');
      fetchUsers();
    } catch (err) {
      const errorMsg = err.response?.data?.message || 'Lỗi reset mật khẩu';
      setError(errorMsg);
      console.error(err);
    }
  };

  const getRoleLabel = (role) => {
    switch (String(role || '').toUpperCase()) {
      case 'ADMIN':
        return 'Admin';
      case 'OWNER':
        return 'Owner';
      case 'MANAGER':
        return 'Quản lý (Manager)';
      case 'TECHNICIAN':
        return 'Kỹ thuật (Technician)';
      case 'WORKER':
        return 'Công nhân (Worker)';
      case 'ACCOUNTANT':
        return 'Kế toán (Accountant)';
      case 'STOREKEEPER':
        return 'Quản lý kho (Storekeeper)';
      default:
        return 'Không xác định';
    }
  };

  if (loading) {
    return (
      <div className="dashboard">
        <div className="flex-center admin-users__loading-container">
          <div className="spinner"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="dashboard admin-page">
      {error && <div className="alert alert-error">{error}</div>}
      {success && <div className="alert alert-success">{success}</div>}

      <div className="table-container">
        <div className="table-header admin-users__table-header">
          <h2>Danh sách người dùng</h2>
          <button className="btn btn-primary" onClick={() => handleOpenModal()}>
            ➕ Thêm người dùng
          </button>
        </div>

        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                <th>Họ tên</th>
                <th>Tên đăng nhập</th>
                <th>Email</th>
                <th>Số điện thoại</th>
                <th>Vai trò</th>
                <th>Trại nuôi</th>
                <th>Trạng thái</th>
                <th>Hành động</th>
              </tr>
            </thead>
            <tbody>
              {users.length > 0 ? (
                users.map((user) => (
                  <tr key={user.user_id}>
                    <td>{user.full_name}</td>
                    <td>{user.username}</td>
                    <td>{user.email}</td>
                    <td>{user.phone || '-'}</td>
                    <td>{getRoleLabel(user.role)}</td>
                    <td>{user.farm_name || user.farm_id || '-'}</td>
                    <td>
                      <span className={`status-badge ${user.status ? 'status-active' : 'status-inactive'}`}>
                        {user.status ? '✓ Hoạt động' : '✗ Khóa'}
                      </span>
                    </td>
                    <td>
                      <div className="admin-users__table-actions">
                        <button
                          className="btn btn-sm btn-secondary"
                          onClick={() => handleOpenModal(user)}
                          title="Chỉnh sửa"
                        >
                          ✏️
                        </button>
                        {user.status ? (
                          String(user.role || '').toUpperCase() === 'ADMIN' ? (
                            <button
                              className="btn btn-sm btn-danger admin-users__btn-disabled"
                              disabled
                              title="Không thể khóa tài khoản Admin"
                            >
                              🔒
                            </button>
                          ) : (
                            <button
                              className="btn btn-sm btn-danger"
                              onClick={() => handleLockUser(user.user_id)}
                              title="Khóa"
                            >
                              🔒
                            </button>
                          )
                        ) : (
                          <button
                            className="btn btn-sm btn-success"
                            onClick={() => handleUnlockUser(user.user_id)}
                            title="Mở khóa"
                          >
                            🔓
                          </button>
                        )}
                        <button
                          className="btn btn-sm btn-warning"
                          onClick={() => handleResetPassword(user.user_id)}
                          title="Reset mật khẩu"
                        >
                          🔑
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="8" className="admin-users__empty-row">
                    Không có người dùng nào
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="modal" onClick={handleCloseModal}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h2>{selectedUser ? '✏️ Chỉnh sửa người dùng' : '➕ Thêm người dùng mới'}</h2>

            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label>Họ và tên</label>
                <input
                  type="text"
                  name="fullName"
                  value={formData.fullName}
                  onChange={handleChange}
                  required
                />
              </div>

              {!selectedUser && (
                <>
                  <div className="form-group">
                    <label>Tên đăng nhập</label>
                    <input
                      type="text"
                      name="username"
                      value={formData.username}
                      onChange={handleChange}
                      required
                    />
                  </div>

                  <div className="form-group">
                    <label>Vai trò</label>
                    <select name="role" value={formData.role} onChange={handleChange} required>
                      {ROLE_OPTIONS.map((option) => (
                        <option key={option.value} value={option.value}>
                          {option.label}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div className="form-group">
                    <label>Trại nuôi</label>
                    <select name="farmId" value={formData.farmId} onChange={handleChange} required>
                      <option value="">-- Chọn trại nuôi --</option>
                      {farms.map((farm) => (
                        <option key={farm.farm_id} value={farm.farm_id}>
                          {farm.farm_name} ({farm.farm_code})
                        </option>
                      ))}
                    </select>
                  </div>

                  <div className="form-group">
                    <label>Mật khẩu</label>
                    <input
                      type="password"
                      name="password"
                      value={formData.password}
                      onChange={handleChange}
                      placeholder="Nhập mật khẩu"
                      required
                    />
                  </div>
                </>
              )}

              <div className="form-group">
                <label>Số điện thoại</label>
                <input
                  type="tel"
                  name="phone"
                  value={formData.phone}
                  onChange={handleChange}
                  placeholder="Nhập số điện thoại"
                />
              </div>

              <div className="form-group">
                <label>Email</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  required
                />
              </div>

              <div className="admin-users__form-buttons">
                <button type="submit" className="btn btn-primary">
                  💾 Lưu
                </button>
                <button type="button" className="btn btn-secondary" onClick={handleCloseModal}>
                  ❌ Hủy
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminUsers;
